#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
using namespace std;
const int K = 2e6+5;
int n,a[30],mid,cnt;
bool Ans[K];
map<int,vector<int>> mp;
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void DFS1(int x,int sum,int st){
    if(x>mid){mp[sum].pb(st);return;}
    DFS1(x+1,sum+a[x],st|(1<<x-1));
    DFS1(x+1,sum-a[x],st|(1<<x-1));
    DFS1(x+1,sum,st);return;
}
void DFS2(int x,int sum,int st){
    if(x>n){for(int p:mp[-sum])Ans[p|st]=1;return;}
    DFS2(x+1,sum+a[x],st|(1<<x-1));
    DFS2(x+1,sum-a[x],st|(1<<x-1));
    DFS2(x+1,sum,st);return;
}
int main(){
    n=read(),mid=n/2;
    for(int i=1;i<=n;i++)a[i]=read();
    DFS1(1,0,0);DFS2(mid+1,0,0);
    for(int i=1;i<(1<<n);i++)if(Ans[i])cnt++;
    cout<<cnt<<"\n";
    return 0;
}
